from fastapi import WebSocket
from typing import Dict, List, Set
import asyncio

class ConnectionManager:
    def __init__(self):
        # All active connections
        self.active_connections: List[WebSocket] = []
        # Room-based connections: room_id → set of websockets
        self.rooms: Dict[str, Set[WebSocket]] = {}

    async def connect(self, websocket: WebSocket, room_id: str = None):
        await websocket.accept()
        self.active_connections.append(websocket)
        if room_id:
            self.rooms.setdefault(room_id, set()).add(websocket)

    def disconnect(self, websocket: WebSocket, room_id: str = None):
        if websocket in self.active_connections:
            self.active_connections.remove(websocket)
        if room_id and room_id in self.rooms:
            self.rooms[room_id].discard(websocket)
            if not self.rooms[room_id]:
                del self.rooms[room_id]

    async def send_personal(self, message: str, websocket: WebSocket):
        await websocket.send_text(message)

    async def broadcast(self, message: str):
        """Send to all connected clients."""
        disconnected = []
        for connection in self.active_connections:
            try:
                await connection.send_text(message)
            except Exception:
                disconnected.append(connection)
        for ws in disconnected:
            self.active_connections.remove(ws)

    async def broadcast_to_room(self, message: str, room_id: str):
        """Send to all clients in a specific room."""
        if room_id not in self.rooms:
            return
        disconnected = set()
        for connection in list(self.rooms[room_id]):
            try:
                await connection.send_text(message)
            except Exception:
                disconnected.add(connection)
        for ws in disconnected:
            self.disconnect(ws, room_id)

manager = ConnectionManager()

@app.websocket("/ws/chat/{room_id}")
async def chat_endpoint(websocket: WebSocket, room_id: str, username: str = Query(...)):
    await manager.connect(websocket, room_id)
    await manager.broadcast_to_room(
        f'{{"event": "join", "user": "{username}"}}', room_id
    )
    try:
        while True:
            text = await websocket.receive_text()
            await manager.broadcast_to_room(
                f'{{"event": "message", "user": "{username}", "text": "{text}"}}',
                room_id
            )
    except WebSocketDisconnect:
        manager.disconnect(websocket, room_id)
        await manager.broadcast_to_room(
            f'{{"event": "leave", "user": "{username}"}}', room_id
        )

