from pydantic import BaseModel
from typing import Literal, Union, Any
import json

# ── Inbound (client → server) ──────────────────────────────────────────────────
class SubscribeMessage(BaseModel):
    type: Literal["subscribe"]
    channel: str

class UnsubscribeMessage(BaseModel):
    type: Literal["unsubscribe"]
    channel: str

class PingMessage(BaseModel):
    type: Literal["ping"]

ClientMessage = Union[SubscribeMessage, UnsubscribeMessage, PingMessage]

# ── Outbound (server → client) ──────────────────────────────────────────────────
class DataMessage(BaseModel):
    type: Literal["data"] = "data"
    channel: str
    payload: Any

class ErrorMessage(BaseModel):
    type: Literal["error"] = "error"
    code: int
    message: str

class PongMessage(BaseModel):
    type: Literal["pong"] = "pong"

def parse_client_message(raw: str) -> ClientMessage:
    data = json.loads(raw)
    msg_type = data.get("type")
    dispatch = {
        "subscribe": SubscribeMessage,
        "unsubscribe": UnsubscribeMessage,
        "ping": PingMessage,
    }
    cls = dispatch.get(msg_type)
    if not cls:
        raise ValueError(f"Unknown message type: {msg_type}")
    return cls(**data)

@app.websocket("/ws/feed")
async def structured_feed(websocket: WebSocket):
    await websocket.accept()
    subscriptions: set[str] = set()

    try:
        while True:
            raw = await websocket.receive_text()
            try:
                msg = parse_client_message(raw)
            except (ValueError, json.JSONDecodeError) as e:
                await websocket.send_json(
                    ErrorMessage(code=4000, message=str(e)).model_dump()
                )
                continue

            if isinstance(msg, SubscribeMessage):
                subscriptions.add(msg.channel)
                await websocket.send_json({"type": "subscribed", "channel": msg.channel})

            elif isinstance(msg, UnsubscribeMessage):
                subscriptions.discard(msg.channel)

            elif isinstance(msg, PingMessage):
                await websocket.send_json(PongMessage().model_dump())

    except WebSocketDisconnect:
        pass

import asyncio
from fastapi import WebSocket, WebSocketDisconnect

PING_INTERVAL = 30  # seconds
PING_TIMEOUT = 10   # seconds

@app.websocket("/ws/keepalive")
async def ws_with_keepalive(websocket: WebSocket):
    await websocket.accept()

    last_pong = asyncio.get_event_loop().time()

    async def ping_loop():
        nonlocal last_pong
        while True:
            await asyncio.sleep(PING_INTERVAL)
            try:
                await websocket.send_json({"type": "ping"})
                # Wait for pong
                deadline = asyncio.get_event_loop().time() + PING_TIMEOUT
                while asyncio.get_event_loop().time() < deadline:
                    if last_pong > asyncio.get_event_loop().time() - PING_INTERVAL:
                        break
                    await asyncio.sleep(0.5)
                else:
                    # No pong received — close stale connection
                    await websocket.close(code=1001, reason="Ping timeout")
                    return
            except Exception:
                return

    async def message_loop():
        nonlocal last_pong
        try:
            while True:
                msg = await websocket.receive_json()
                if msg.get("type") == "pong":
                    last_pong = asyncio.get_event_loop().time()
                else:
                    await handle_message(msg)
        except WebSocketDisconnect:
            pass

    await asyncio.gather(ping_loop(), message_loop())

import redis.asyncio as aioredis
import asyncio
import json
from fastapi import WebSocket, WebSocketDisconnect

redis = aioredis.from_url("redis://localhost")

class PubSubConnectionManager:
    def __init__(self):
        self.local_connections: Dict[str, Set[WebSocket]] = {}

    async def subscribe_local(self, room_id: str, websocket: WebSocket):
        self.local_connections.setdefault(room_id, set()).add(websocket)

    def unsubscribe_local(self, room_id: str, websocket: WebSocket):
        if room_id in self.local_connections:
            self.local_connections[room_id].discard(websocket)

    async def publish(self, room_id: str, message: dict):
        """Publish to Redis — all instances receive this."""
        await redis.publish(f"room:{room_id}", json.dumps(message))

    async def listen(self, room_id: str):
        """Subscribe to Redis channel and forward to local connections."""
        pubsub = redis.pubsub()
        await pubsub.subscribe(f"room:{room_id}")
        async for raw_message in pubsub.listen():
            if raw_message["type"] != "message":
                continue
            data = json.loads(raw_message["data"])
            local_sockets = list(self.local_connections.get(room_id, set()))
            dead = set()
            for ws in local_sockets:
                try:
                    await ws.send_json(data)
                except Exception:
                    dead.add(ws)
            for ws in dead:
                self.local_connections[room_id].discard(ws)

pubsub_manager = PubSubConnectionManager()

@app.websocket("/ws/room/{room_id}")
async def room_ws(websocket: WebSocket, room_id: str):
    await websocket.accept()
    await pubsub_manager.subscribe_local(room_id, websocket)

    # Start listener task for this room if not already running
    listener_task = asyncio.create_task(pubsub_manager.listen(room_id))

    try:
        while True:
            text = await websocket.receive_text()
            await pubsub_manager.publish(room_id, {
                "text": text,
                "room": room_id
            })
    except WebSocketDisconnect:
        pubsub_manager.unsubscribe_local(room_id, websocket)
        listener_task.cancel()

